package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.util.Collections;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CartTest {

  private Cart cart;
  private List<LineItem> lineItems;
  private String buyerName;
  private String creditCard;

  @BeforeEach
  public void setUp() throws Exception {
    lineItems = Collections.emptyList();
    buyerName = "John Doe";
    creditCard = "1234-5678-9876-5432";

    // Use reflection to invoke the constructor since fields are final
    Constructor<Cart> constructor = Cart.class.getDeclaredConstructor(List.class, String.class, String.class);
    constructor.setAccessible(true);
    cart = constructor.newInstance(lineItems, buyerName, creditCard);
  }

  @Test
  public void testGetCreditCard() {
    assertEquals(creditCard, cart.getCreditCard());
  }
}
